    function notifyMemberEvent(title, preview, memberId = null) {
        notifyOrderCreated(
            title,
            preview,
            memberId ? 'View Member' : 'View Members',
            () => {
                pageTitle.textContent = 'Members';
                if (memberId && getMemberById(memberId)) {
                    membersView = 'detail';
                    activeMemberId = memberId;
                } else {
                    membersView = 'list';
                    activeMemberId = null;
                }
                renderMembersPage();
            }
        );
    }

