            for (let i = 0; i < payee.id.length; i++) _seed = (_seed * 31 + payee.id.charCodeAt(i)) & 0xffff;
            const _rand = () => { _seed = (_seed * 1103515245 + 12345) & 0x7fffffff; return _seed / 0x7fffffff; };
            const pmW = payee.wallets?.[0], pmB = payee.banks?.[0];
